    <section className="projects">
      <h2>Projects</h2>
      <div className="project-list">
        <div className="project-item">
          <h3>SyncPulse</h3>
          <p>Empty</p>
        </div>
        <div className="project-item">
          <h3>PuzzleFlix</h3>
          <p>Empty</p>
        </div>
        <div className="project-item">
          <h3>Games</h3>
          <p>Empty</p>
        </div>
      </div>
    </section>
  );
};

export default Projects;
